import { NAV_LINKS } from "..";

export default function Navbar({ active, setActive }) {
  return (
    <nav className="pb-navbar">
      <Logo />
      <ul className="pb-nav-links">
        {NAV_LINKS.map((link) => (
          <li key={link}>
            <button
              className={`pb-nav-link${active === link ? " active" : ""}`}
              onClick={() => setActive(link)}
            >
              {link}
            </button>
          </li>
        ))}
      </ul>
    </nav>
  );
}

function Logo() {
  return (
    <div className="pb-brand">
      <div className="pb-logo">PB</div>
      <span className="pb-brand-text">Palheta Barbearia</span>
    </div>
  );
}
